// Time:  O(n)
// Space: O(k)

class Solution {
public:
    vector<int> mostCompetitive(vector<int>& nums, int k) {
        vector<int> stk;
        for (int i = 0; i < size(nums); ++i) {
            while (!empty(stk) && stk.back() > nums[i] &&
                   size(stk) + (size(nums) - i) > k) {
                stk.pop_back();
            }
            if (size(stk) < k) {
                stk.emplace_back(nums[i]);
            }
        }
        return stk;
    }
};

# Time:  O(n)
# Space: O(k)

class Solution(object):
    def mostCompetitive(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: List[int]
        """
        stk = []
        for i, x in enumerate(nums):
            while stk and stk[-1] > x and len(stk)+(len(nums)-i) > k:
                stk.pop()
            if len(stk) < k:
                stk.append(x)
        return stk
